import{_ as e,W as t,X as n,Y as g,$ as a,a0 as i,a1 as c}from"./framework-f38b131a.js";const d={},r=a("h1",{id:"导语",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#导语","aria-hidden":"true"},"#"),i(" 导语")],-1),o=a("p",null,"有时候，我们需要单独给首页或特定页设置页眉页脚。",-1),p=a("blockquote",null,[a("p",null,[i("例如在学术写作中，有的期刊会要求在第一页设置这种格式的标注： "),a("img",{src:"https://blog.kevin2li.top/static/img/8709e3f12c92b287f02f4c0340f9a93b.image.png",alt:"image.png",loading:"lazy"})])],-1),h=a("p",null,"但是，默认设置下，office所有页面的页脚内容是一样的，改动某一页的页脚其他页面也会跟着改变。如何实现上述效果呢？",-1),s=c('<h1 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h1><p><strong>思路：</strong> word和wps中同一节下的页面页眉页脚都是相同的，如果要对特定页面进行单独设置页眉页脚，就要把它放在独立的节中</p><p>下面以两种常见的办公软件Word和WPS分别介绍使用方法。</p><h2 id="wps" tabindex="-1"><a class="header-anchor" href="#wps" aria-hidden="true">#</a> WPS</h2><h3 id="_1-插入分节符" tabindex="-1"><a class="header-anchor" href="#_1-插入分节符" aria-hidden="true">#</a> 1. 插入分节符</h3><p>以首页单独设置页脚为例，在首页尾部插入一个“下一页分节符”。(如果是中间页，需要在该页尾部插入一个“下一页分节符”以及该页的上一页尾部插入一个“下一页分节符”)</p><figure><img src="https://blog.kevin2li.top/static/img/02ffdb6e0807afb9708554454054f023.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><figure><img src="https://blog.kevin2li.top/static/img/b6d6538c0378146def867c12e23437c9.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h3 id="_2-在下一节取消-同前节" tabindex="-1"><a class="header-anchor" href="#_2-在下一节取消-同前节" aria-hidden="true">#</a> 2. 在下一节取消“同前节”</h3><p>在目标页面的下一节的页面的页眉页脚设置中取消勾选“同前节”</p><figure><img src="https://blog.kevin2li.top/static/img/8142fdf147c55608b15b6272aeafdefc.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h3 id="_3-编辑目标页面页脚" tabindex="-1"><a class="header-anchor" href="#_3-编辑目标页面页脚" aria-hidden="true">#</a> 3. 编辑目标页面页脚</h3><p>设置目标页面的页脚内容，也可以设置页码等 <img src="https://blog.kevin2li.top/static/img/2062a13a5edeed9dbbe0f10bf205d8b5.image.png" alt="image.png" loading="lazy"></p><h2 id="word" tabindex="-1"><a class="header-anchor" href="#word" aria-hidden="true">#</a> Word</h2><h3 id="_1-插入分节符-1" tabindex="-1"><a class="header-anchor" href="#_1-插入分节符-1" aria-hidden="true">#</a> 1. 插入分节符</h3><p>以首页单独设置页脚为例，在首页尾部插入一个“下一页分节符”。(如果是中间页，需要在该页尾部插入一个“下一页分节符”以及该页的上一页尾部插入一个“下一页分节符”) <img src="https://blog.kevin2li.top/static/img/21e349a5b25b1dc369441c35b0074cb3.image.png" alt="image.png" loading="lazy"></p><figure><img src="https://blog.kevin2li.top/static/img/69b524cb444c0e0ceb121e4c247861cc.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h3 id="_2-在下一节取消-链接到前一节" tabindex="-1"><a class="header-anchor" href="#_2-在下一节取消-链接到前一节" aria-hidden="true">#</a> 2. 在下一节取消“链接到前一节”</h3><p>在目标页面的下一节的页面的页眉页脚设置中取消勾选“链接到前一节”<br><img src="https://blog.kevin2li.top/static/img/cdf382c92b989e22602af4ea1cc8f9bb.image.png" alt="image.png" loading="lazy"></p><h3 id="_3-编辑目标页面页脚-1" tabindex="-1"><a class="header-anchor" href="#_3-编辑目标页面页脚-1" aria-hidden="true">#</a> 3. 编辑目标页面页脚</h3><p>设置目标页面的页脚内容，也可以设置页码等</p><figure><img src="https://blog.kevin2li.top/static/img/070c9c3b10f3dad059372391c0e25a05.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure>',22);function l(f,m){return t(),n("div",null,[r,o,p,h,g(" more "),s])}const _=e(d,[["render",l],["__file","Office单独设置页眉页脚.html.vue"]]);export{_ as default};
